namespace sv_e951a7687cc24fc09400962b8197ac1b.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@using sv_e951a7687cc24fc09400962b8197ac1b.Services

<h3>Profile</h3>
<hr />

@if (showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Profile saved successfully!
        <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
    </div>
}

<div class="row mb-4">
    <div class="col-md-8">
        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="displayName" @bind:event="oninput" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="email" @bind:event="oninput" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="bio" @bind:event="oninput"></textarea>
        </div>
    </div>
    <div class="col-md-4">
        <div class="text-center">
            <div class="mb-2">
                @if (!string.IsNullOrWhiteSpace(avatarUrl))
                {
                    <img src="@avatarUrl" alt="Avatar" class="rounded-circle"
                         style="width:120px;height:120px;object-fit:cover;" />
                }
                else
                {
                    <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center mx-auto"
                         style="width:120px;height:120px;">
                        <span class="text-white fs-1">
                            @(displayName.Length > 0 ? displayName[0].ToString().ToUpper() : "?")
                        </span>
                    </div>
                }
            </div>
            <label class="form-label fw-semibold">Avatar URL</label>
            <input type="url" class="form-control form-control-sm" @bind="avatarUrl" @bind:event="oninput" />
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@(!HasChanges || isSaving)">
        @if (isSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Changes
    </button>
    <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@(!HasChanges)">
        Discard Changes
    </button>
</div>

@code {
    [Parameter] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string bio = "";
    private string avatarUrl = "";
    private bool showSuccess;
    private bool isSaving;
    private UserProfile? lastProfile;

    private bool HasChanges =>
        displayName != (Profile?.DisplayName ?? "")
        || email != (Profile?.Email ?? "")
        || bio != (Profile?.Bio ?? "")
        || avatarUrl != (Profile?.AvatarUrl ?? "");

    protected override void OnParametersSet()
    {
        if (Profile != lastProfile)
        {
            lastProfile = Profile;
            displayName = Profile.DisplayName;
            email = Profile.Email;
            bio = Profile.Bio;
            avatarUrl = Profile.AvatarUrl;
        }
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            showSuccess = true;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void Discard()
    {
        displayName = Profile.DisplayName;
        email = Profile.Email;
        bio = Profile.Bio;
        avatarUrl = Profile.AvatarUrl;
        showSuccess = false;
    }
}

@using sv_e951a7687cc24fc09400962b8197ac1b.Services

<h3>Notifications</h3>
<hr />

@if (showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Preferences saved successfully!
        <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
    </div>
}

<div class="mb-4">
    <h5>General</h5>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
        <label class="form-check-label" for="emailNotif">Email Notifications</label>
    </div>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
        <label class="form-check-label" for="pushNotif">Push Notifications</label>
    </div>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
    </div>
</div>

<div class="mb-4">
    <h5>Muted Channels</h5>
    <p class="text-muted small">Select channels to mute notifications from.</p>
    @foreach (var channel in availableChannels)
    {
        var ch = channel;
        var isMuted = mutedChannels.Contains(ch);
        <div class="form-check mb-1">
            <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                   checked="@isMuted" @onchange="e => ToggleChannel(ch, (bool)e.Value!)" />
            <label class="form-check-label" for="@($"ch-{ch}")">@ch</label>
        </div>
    }
</div>

<button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
    @if (isSaving)
    {
        <span class="spinner-border spinner-border-sm me-1"></span>
    }
    Save Preferences
</button>

@code {
    [Parameter] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool showSuccess;
    private bool isSaving;
    private NotificationPrefs? lastPrefs;

    private static readonly string[] availableChannels =
        ["General", "Announcements", "Updates", "Marketing", "Engineering", "Support"];

    protected override void OnParametersSet()
    {
        if (Prefs != lastPrefs)
        {
            lastPrefs = Prefs;
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) mutedChannels.Add(channel);
        else mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            showSuccess = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

@using sv_e951a7687cc24fc09400962b8197ac1b.Services

@if (Session is not null)
{
    <div class="revoke-overlay" @onclick="OnCancel.InvokeAsync">
        <div class="revoke-dialog" @onclick:stopPropagation="true">
            <div class="card shadow">
                <div class="card-body">
                    <h5 class="card-title">Revoke Session</h5>
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?
                    </p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                    <div class="d-flex justify-content-end gap-2">
                        <button class="btn btn-outline-secondary" @onclick="OnCancel.InvokeAsync">Cancel</button>
                        <button class="btn btn-danger" @onclick="OnConfirm.InvokeAsync">Revoke</button>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
}

.revoke-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.revoke-dialog {
    max-width: 450px;
    width: 90%;
}

@using sv_e951a7687cc24fc09400962b8197ac1b.Services

<h3>Security</h3>
<hr />

<ChangePasswordPanel OnChangePassword="OnPasswordChanged" />

<div class="card mb-4">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <h5 class="mb-1">Two-Factor Authentication</h5>
                <p class="text-muted mb-0 small">Add an extra layer of security to your account.</p>
            </div>
            <div class="d-flex align-items-center gap-2">
                <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox"
                           checked="@Security.TwoFactorEnabled" disabled />
                </div>
            </div>
        </div>
        @if (Security.LastPasswordChange.HasValue)
        {
            <p class="text-muted small mt-2 mb-0">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>
</div>

<div class="mb-4">
    <h5>Active Sessions</h5>
    <p class="text-muted small">Devices currently signed in to your account.</p>
    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Security.Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-primary ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                        <td class="text-end">
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => sessionToRevoke = session">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

<RevokeSessionDialog Session="@sessionToRevoke"
                      OnConfirm="ConfirmRevoke"
                      OnCancel="() => sessionToRevoke = null" />

@code {
    [Parameter] public SecuritySettings Security { get; set; } = default!;
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<(string Current, string New)> OnPasswordChanged { get; set; }
    [Parameter] public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? sessionToRevoke;

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnSessionRevoked.InvokeAsync(sessionToRevoke.Id);
            sessionToRevoke = null;
        }
    }
}

@using sv_e951a7687cc24fc09400962b8197ac1b.Services

<h3>Appearance</h3>
<hr />

@if (showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Appearance settings saved!
        <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
    </div>
