<h3>Notifications</h3>
<hr />

@if (showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Preferences saved successfully!
        <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
    </div>
}

<div class="mb-4">
    <h5>General</h5>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
        <label class="form-check-label" for="emailNotif">Email Notifications</label>
    </div>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
        <label class="form-check-label" for="pushNotif">Push Notifications</label>
    </div>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
    </div>
</div>

<div class="mb-4">
    <h5>Muted Channels</h5>
    <p class="text-muted small">Select channels to mute notifications from.</p>
    @foreach (var channel in availableChannels)
    {
        var ch = channel;
        var isMuted = mutedChannels.Contains(ch);
        <div class="form-check mb-1">
            <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                   checked="@isMuted" @onchange="e => ToggleChannel(ch, (bool)e.Value!)" />
            <label class="form-check-label" for="@($"ch-{ch}")">@ch</label>
        </div>
    }
</div>

<button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
    @if (isSaving)
    {
        <span class="spinner-border spinner-border-sm me-1"></span>
    }
    Save Preferences
</button>

@code {
    [Parameter] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool showSuccess;
    private bool isSaving;
    private NotificationPrefs? lastPrefs;

    private static readonly string[] availableChannels =
        ["General", "Announcements", "Updates", "Marketing", "Engineering", "Support"];

    protected override void OnParametersSet()
    {
        if (Prefs != lastPrefs)
        {
            lastPrefs = Prefs;
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) mutedChannels.Add(channel);
        else mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            showSuccess = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}
"}

{"path": "/tmp/sv-e951a7687cc24fc09400962b8197ac1b/Components/Pages/Settings/ChangePasswordPanel.razor", "file_text": "<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer;" @onclick="() => isExpanded = !isExpanded">
        <h5 class="mb-0">Change Password</h5>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </div>
    @if (isExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success">@successMessage</div>
            }
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" style="max-width:400px;" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" style="max-width:400px;" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" style="max-width:400px;" @bind="confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool isExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool isSubmitting;

    private async Task UpdatePasswordAsync()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            errorMessage = "New password must be at least 8 characters.";
            return;
        }

        isSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            successMessage = "Password updated successfully.";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
"}

