@using sv_e951a7687cc24fc09400962b8197ac1b.Services

<h3>Notifications</h3>
<hr />

@if (showSuccess)
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        Preferences saved successfully!
        <button type="button" class="btn-close" @onclick="() => showSuccess = false"></button>
    </div>
}

<div class="mb-4">
    <h5>General</h5>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
        <label class="form-check-label" for="emailNotif">Email Notifications</label>
    </div>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
        <label class="form-check-label" for="pushNotif">Push Notifications</label>
    </div>
    <div class="form-check form-switch mb-2">
        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
    </div>
</div>

<div class="mb-4">
    <h5>Muted Channels</h5>
    <p class="text-muted small">Select channels to mute notifications from.</p>
    @foreach (var channel in availableChannels)
    {
        var ch = channel;
        var isMuted = mutedChannels.Contains(ch);
        <div class="form-check mb-1">
            <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                   checked="@isMuted" @onchange="e => ToggleChannel(ch, (bool)e.Value!)" />
            <label class="form-check-label" for="@($"ch-{ch}")">@ch</label>
        </div>
    }
</div>

<button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
    @if (isSaving)
    {
        <span class="spinner-border spinner-border-sm me-1"></span>
    }
    Save Preferences
</button>

@code {
    [Parameter] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool showSuccess;
    private bool isSaving;
    private NotificationPrefs? lastPrefs;

    private static readonly string[] availableChannels =
        ["General", "Announcements", "Updates", "Marketing", "Engineering", "Support"];

    protected override void OnParametersSet()
    {
        if (Prefs != lastPrefs)
        {
            lastPrefs = Prefs;
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) mutedChannels.Add(channel);
        else mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            showSuccess = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

