+}
+
+<div class="row">
+    <div class="col-md-6">
+        <div class="mb-4">
+            <h5>Theme</h5>
+            @foreach (var t in themes)
+            {
+                <div class="form-check">
+                    <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
+                           value="@t" checked="@(theme == t)" @onchange="() => theme = t" />
+                    <label class="form-check-label" for="@($"theme-{t}")">@t</label>
+                </div>
+            }
+        </div>
+
+        <div class="mb-4">
+            <h5>Font Size</h5>
+            @foreach (var fs in fontSizes)
+            {
+                <div class="form-check">
+                    <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
+                           value="@fs" checked="@(fontSize == fs)" @onchange="() => fontSize = fs" />
+                    <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
+                </div>
+            }
+        </div>
+
+        <div class="mb-4">
+            <h5>Language</h5>
+            <select class="form-select" style="max-width:250px;" @bind="language">
+                @foreach (var lang in languages)
+                {
+                    <option value="@lang">@lang</option>
+                }
+            </select>
+        </div>
+
+        <div class="mb-4">
+            <div class="form-check form-switch">
+                <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
+                <label class="form-check-label" for="compactMode">Compact Mode</label>
+            </div>
+        </div>
+
+        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
+            @if (isSaving)
+            {
+                <span class="spinner-border spinner-border-sm me-1"></span>
+            }
+            Save
+        </button>
+    </div>
+
+    <div class="col-md-6">
+        <h5>Preview</h5>
+        <div class="border rounded" style="@PreviewContainerStyle">
+            <h6 style="@FontStyle">Dashboard</h6>
+            <p style="@FontStyle" class="mb-2">
+                This is a preview of how your content will appear with the selected settings.
+            </p>
+            <button class="btn btn-sm @ButtonClass" style="@FontStyle" disabled>
+                Sample Button
+            </button>
+            <div class="mt-2">
+                <input type="text" class="form-control form-control-sm"
+                       placeholder="Sample input" style="@InputStyle" disabled />
+            </div>
+            <p class="mt-2 mb-0 small" style="@FontStyle">
+                Language: @language &bull; Font: @fontSize &bull; Compact: @(compactMode ? "On" : "Off")
+            </p>
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter] public AppearanceSettings Settings { get; set; } = default!;
+    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }
+
+    private string theme = "Light";
+    private string fontSize = "Medium";
+    private string language = "English";
+    private bool compactMode;
+    private bool showSuccess;
+    private bool isSaving;
+    private AppearanceSettings? lastSettings;
+
+    private static readonly string[] themes = ["Light", "Dark", "System"];
+    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
+    private static readonly string[] languages =
+        ["English", "Spanish", "French", "German", "Japanese", "Chinese"];
+
+    protected override void OnParametersSet()
+    {
+        if (Settings != lastSettings)
+        {
+            lastSettings = Settings;
+            theme = Settings.Theme;
+            fontSize = Settings.FontSize;
+            language = Settings.Language;
+            compactMode = Settings.CompactMode;
+        }
+    }
+
+    private string PreviewContainerStyle
+    {
+        get
+        {
+            var bg = theme == "Dark" ? "#1e1e1e" : "#ffffff";
+            var color = theme == "Dark" ? "#e0e0e0" : "#212529";
+            var padding = compactMode ? "0.75rem" : "1.5rem";
+            return $"background:{bg};color:{color};padding:{padding};transition:all 0.3s ease;";
+        }
+    }
+
+    private string FontStyle
+    {
+        get
+        {
+            var size = fontSize switch
+            {
+                "Small" => "0.85rem",
+                "Large" => "1.15rem",
+                _ => "1rem"
+            };
+            return $"font-size:{size};";
+        }
+    }
+
+    private string ButtonClass => theme == "Dark" ? "btn-outline-light" : "btn-outline-dark";
+
+    private string InputStyle
+    {
+        get
+        {
+            var bg = theme == "Dark" ? "#2d2d2d" : "#ffffff";
+            var border = theme == "Dark" ? "#555" : "#ced4da";
+            var color = theme == "Dark" ? "#e0e0e0" : "#212529";
+            return $"background:{bg};border-color:{border};color:{color};";
+        }
+    }
+
+    private async Task SaveAsync()
+    {
+        isSaving = true;
+        try
+        {
+            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
+            await OnSave.InvokeAsync(updated);
+            showSuccess = true;
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+}
